/**
 * Web Vitals monitoring using the native Performance API.
 *
 * Tracks Core Web Vitals (LCP, FID/INP, CLS) and custom metrics
 * without requiring the `web-vitals` npm package.
 *
 * @module lib/performance/web-vitals
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Name of a Core Web Vital metric. */
export type WebVitalName = 'CLS' | 'FID' | 'INP' | 'LCP' | 'FCP' | 'TTFB';

/** Rating returned alongside a metric value. */
export type WebVitalRating = 'good' | 'needs-improvement' | 'poor';

/** A single metric report. */
export interface WebVitalMetric {
  /** Metric identifier */
  name: WebVitalName;
  /** Measured value (ms for timing metrics, unitless for CLS) */
  value: number;
  /** Quality rating */
  rating: WebVitalRating;
  /** Navigation type (navigate, reload, back_forward, prerender) */
  navigationType: string;
  /** Unix timestamp when the metric was captured */
  timestamp: number;
}

/** Callback invoked for each captured metric. */
export type WebVitalReportCallback = (metric: WebVitalMetric) => void;

// ---------------------------------------------------------------------------
// Thresholds — based on https://web.dev/vitals/
// ---------------------------------------------------------------------------

export interface VitalThresholds {
  good: number;
  poor: number;
}

export const VITAL_THRESHOLDS: Record<WebVitalName, VitalThresholds> = {
  CLS:  { good: 0.1,  poor: 0.25  },
  FID:  { good: 100,  poor: 300   },
  INP:  { good: 200,  poor: 500   },
  LCP:  { good: 2500, poor: 4000  },
  FCP:  { good: 1800, poor: 3000  },
  TTFB: { good: 800,  poor: 1800  },
};

// ---------------------------------------------------------------------------
// Pure helpers (easily testable)
// ---------------------------------------------------------------------------

/**
 * Determine the quality rating for a given metric value.
 */
export function getRating(name: WebVitalName, value: number): WebVitalRating {
  const t = VITAL_THRESHOLDS[name];
  if (!t) return 'good';
  if (value <= t.good) return 'good';
  if (value <= t.poor) return 'needs-improvement';
  return 'poor';
}

/**
 * Build a metric object from raw data.
 */
export function buildMetric(
  name: WebVitalName,
  value: number,
  navigationType: string = 'navigate',
): WebVitalMetric {
  return {
    name,
    value: Math.round(value * 1000) / 1000,   // 3 decimal places
    rating: getRating(name, value),
    navigationType,
    timestamp: Date.now(),
  };
}

/**
 * Format a metric value for human-readable display.
 */
export function formatMetricValue(name: WebVitalName, value: number): string {
  if (name === 'CLS') {
    return value.toFixed(3);
  }
  return `${Math.round(value)}ms`;
}

/**
 * Get a colour code for a rating.
 */
export function ratingColor(rating: WebVitalRating): string {
  switch (rating) {
    case 'good':              return '#0cce6b';
    case 'needs-improvement': return '#ffa400';
    case 'poor':              return '#ff4e42';
  }
}

/**
 * Calculate an overall performance score (0-100) from a set of metrics.
 *
 * Weights based on Lighthouse 10 scoring:
 *   LCP 25%, FID/INP 30%, CLS 25%, FCP 10%, TTFB 10%
 *
 * Each individual score is 100 when value ≤ good, 0 when value ≥ poor,
 * and linearly interpolated in between.
 */
export const METRIC_WEIGHTS: Partial<Record<WebVitalName, number>> = {
  LCP:  0.25,
  INP:  0.30,
  CLS:  0.25,
  FCP:  0.10,
  TTFB: 0.10,
};

/**
 * Convert a single metric value to a 0-100 score.
 */
export function metricToScore(name: WebVitalName, value: number): number {
  const t = VITAL_THRESHOLDS[name];
  if (!t) return 100;
  if (value <= t.good) return 100;
  if (value >= t.poor) return 0;
  // Linear interpolation
  const ratio = (value - t.good) / (t.poor - t.good);
  return Math.round(100 * (1 - ratio));
}

/**
 * Compute a weighted overall score from a map of metric values.
 */
export function computeOverallScore(
  metrics: Partial<Record<WebVitalName, number>>,
): number {
  let totalWeight = 0;
  let weightedSum = 0;

  const entries = Object.entries(METRIC_WEIGHTS) as Array<[WebVitalName, number]>;
  for (const [name, weight] of entries) {
    const val = metrics[name];
    if (val === undefined) continue;
    weightedSum += metricToScore(name, val) * weight;
    totalWeight += weight;
  }

  if (totalWeight === 0) return 100;
  return Math.round(weightedSum / totalWeight);
}

/**
 * Summarise a set of metrics into a human-readable report.
 */
export function summariseMetrics(
  metrics: Partial<Record<WebVitalName, number>>,
): string {
  const lines: string[] = [];
  for (const name of Object.keys(VITAL_THRESHOLDS) as WebVitalName[]) {
    const val = metrics[name];
    if (val === undefined) continue;
    const rating = getRating(name, val);
    lines.push(`${name}: ${formatMetricValue(name, val)} (${rating})`);
  }
  const score = computeOverallScore(metrics);
  lines.push(`Overall score: ${score}/100`);
  return lines.join('\n');
}

// ---------------------------------------------------------------------------
// Browser-side observers (guarded for SSR safety)
// ---------------------------------------------------------------------------

/**
 * Detect the navigation type from the Navigation Timing API.
 */
export function getNavigationType(): string {
  if (typeof window === 'undefined') return 'unknown';
  const nav = performance?.getEntriesByType?.('navigation')?.[0] as PerformanceNavigationTiming | undefined;
  return nav?.type ?? 'navigate';
}

/**
 * Observe Largest Contentful Paint.
 */
export function observeLCP(callback: WebVitalReportCallback): (() => void) | undefined {
  if (typeof window === 'undefined' || typeof PerformanceObserver === 'undefined') return undefined;
  try {
    const po = new PerformanceObserver((list) => {
      const entries = list.getEntries();
      const last = entries[entries.length - 1];
      if (last) {
        callback(buildMetric('LCP', last.startTime, getNavigationType()));
      }
    });
    po.observe({ type: 'largest-contentful-paint', buffered: true });
    return () => po.disconnect();
  } catch {
    return undefined;
  }
}

/**
 * Observe First Input Delay.
 */
export function observeFID(callback: WebVitalReportCallback): (() => void) | undefined {
  if (typeof window === 'undefined' || typeof PerformanceObserver === 'undefined') return undefined;
  try {
    const po = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        const fid = entry as PerformanceEventTiming;
        callback(buildMetric('FID', fid.processingStart - fid.startTime, getNavigationType()));
      }
    });
    po.observe({ type: 'first-input', buffered: true });
    return () => po.disconnect();
  } catch {
    return undefined;
  }
}

/**
 * Observe Cumulative Layout Shift.
 */
export function observeCLS(callback: WebVitalReportCallback): (() => void) | undefined {
  if (typeof window === 'undefined' || typeof PerformanceObserver === 'undefined') return undefined;
  try {
    let clsValue = 0;
    let sessionValue = 0;
    let sessionEntries: PerformanceEntry[] = [];

    const po = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        // Only count layout shifts without recent input
        const lsEntry = entry as PerformanceEntry & { hadRecentInput?: boolean; value?: number };
        if (lsEntry.hadRecentInput) continue;

        const firstEntry = sessionEntries[0];
        const lastEntry = sessionEntries[sessionEntries.length - 1];

        // If the entry is within 1s of the previous entry and less than 5s
        // from the first entry in the session, include it in the current session.
        if (
          sessionValue &&
          lastEntry &&
          entry.startTime - lastEntry.startTime < 1000 &&
          firstEntry &&
          entry.startTime - firstEntry.startTime < 5000
        ) {
          sessionValue += lsEntry.value ?? 0;
          sessionEntries.push(entry);
        } else {
          sessionValue = lsEntry.value ?? 0;
          sessionEntries = [entry];
        }

        if (sessionValue > clsValue) {
          clsValue = sessionValue;
          callback(buildMetric('CLS', clsValue, getNavigationType()));
        }
      }
    });
    po.observe({ type: 'layout-shift', buffered: true });
    return () => po.disconnect();
  } catch {
    return undefined;
  }
}

/**
 * Observe First Contentful Paint.
 */
export function observeFCP(callback: WebVitalReportCallback): (() => void) | undefined {
  if (typeof window === 'undefined' || typeof PerformanceObserver === 'undefined') return undefined;
  try {
    const po = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        if (entry.name === 'first-contentful-paint') {
          callback(buildMetric('FCP', entry.startTime, getNavigationType()));
          po.disconnect();
        }
      }
    });
    po.observe({ type: 'paint', buffered: true });
    return () => po.disconnect();
  } catch {
    return undefined;
  }
}

/**
 * Measure Time to First Byte from the Navigation Timing API.
 */
export function measureTTFB(callback: WebVitalReportCallback): void {
  if (typeof window === 'undefined') return;
  try {
    const nav = performance?.getEntriesByType?.('navigation')?.[0] as PerformanceNavigationTiming | undefined;
    if (nav) {
      callback(buildMetric('TTFB', nav.responseStart - nav.requestStart, getNavigationType()));
    }
  } catch {
    // Silently ignore if Navigation Timing is not available
  }
}

/**
 * Start observing all Core Web Vitals and return a cleanup function.
 */
export function observeAllVitals(callback: WebVitalReportCallback): () => void {
  const cleanups: Array<(() => void) | undefined> = [
    observeLCP(callback),
    observeFID(callback),
    observeCLS(callback),
    observeFCP(callback),
  ];

  measureTTFB(callback);

  return () => {
    for (const cleanup of cleanups) {
      cleanup?.();
    }
  };
}
